def assemble_context(retrieval_result):
    query_emb = model.encode([retrieval_result['query']])
    relevant_docs = []
    for doc, score in zip(retrieval_result['docs'], retrieval_result['scores']):
        doc_emb = model.encode([doc['content']])
        similarity = np.dot(query_emb, doc_emb.T).squeeze()
        if similarity > 0.7:
            relevant_docs.append(doc)
    context = "\n".join([f"[DOC {i}]: {d['content']}" for i, d in enumerate(relevant_docs)])
    return {'context': context, 'sources': [d['source'] for d in relevant_docs]}

assembler.register_for_llm(name="assemble", func=assemble_context)

def synthesize_response(context_data, query):
    prompt = f"""Answer using ONLY this context:
{context_data['context']}

Query: {query}
Cite sources as [DOC X] inline."""
    response = synthesizer.generate_reply(prompt)
    return {
        'answer': response,
        'sources': context_data['sources'],
        'citations': extract_citations(response)
    }

