def vex_source_check(message, context_docs):
    results = vex.verify(
        task='source-faithfulness',
        inputs={
            'claim': message['answer'],
            'sources': [doc['content'] for doc in context_docs],
            'citations': message['citations']
        },
        verifiers=['entailment-nli']
    )
    return {
        'approved': results['pass_rate'] > 0.9,
        'reply': message if results['pass_rate'] > 0.9 else 'Sources do not support this answer',
        'score': results['pass_rate']
    }

def vex_relevance_filter(retrieval):
    verdict = vex.verify(
        task='context-relevance',
        inputs={
            'query': retrieval['query'],
            'documents': [d['content'] for d in retrieval['docs']],
            'scores': retrieval['scores']
        },
        threshold=0.75
    )
    if not verdict['approved']:
        return {'error': 'Irrelevant context detected', 'retry': True}
    return retrieval

conversation_history = []

def vex_loop_detector(current_message, agents):
    conversation_history.append(current_message)
    if len(conversation_history) > 10:
        loop_risk = vex.verify(
            task='conversation-drift',
            inputs={'history': conversation_history[-8:]},
            verifiers=['semantic-similarity']
        )
        if loop_risk['loop_detected']:
            return {'terminate': True, 'reason': 'Infinite loop detected'}
    return {'continue': True}
